var seed = GetInt(parameters, "seed", context.Seed);
var time = GetFloat(parameters, "time", 0f);
var density = GetFloat(parameters, "density", 0.5f);
var speed = GetFloat(parameters, "speed", 0.5f);
var wind = GetFloat(parameters, "wind", 0f);
var size2 = GetInt(parameters, "size", 2);
var sway = GetFloat(parameters, "sway", 0.3f);
var pixelSize = Math.Max(1, GetInt(parameters, "pixelSize", 1));

var size = context.TileSize;
var result = new PixelBuffer(size, size);

// Grid-based snowflake distribution
var gridSize = Math.Max(5, (int)(15f * density));
var cellW = size / (float)gridSize;
var cellH = size / (float)gridSize;

var fallDist = time * speed * size;
var windBase = wind * size * 0.12f;

for (var gy = 0; gy < gridSize; gy++)
{
    for (var gx = 0; gx < gridSize; gx++)
    {
        var h = HashToUnit(gx * 31 + gy * 17, seed, 111);
        if (h > density) continue;

        // Position within cell
        var xOff = HashToUnit(gx * 7 + gy * 13, seed + 50, 222);
        var yOff = HashToUnit(gx * 11 + gy * 5, seed + 100, 333);

        // Sway: sinusoidal horizontal drift
        var swayAmount = sway * cellW * 0.4f;
        var swayPhase = (gx * 23 + gy * 19) * 0.1f + seed * 0.01f;
        var swayOff = (int)(MathF.Sin(time * MathF.PI * 2f * 0.5f + swayPhase) * swayAmount);

        var sx = (int)((gx + xOff) * cellW + windBase + swayOff) % size;
        if (sx < 0) sx += size;
        sx = (sx / pixelSize) * pixelSize;

        var rawY = (gy * cellH + yOff * cellH + fallDist) % (size + pixelSize * 4);
        var sy = (int)(rawY - pixelSize * 2);
        if (sy < 0 || sy >= size) continue;
        sy = (sy / pixelSize) * pixelSize;

        // Draw snowflake as soft circle
        var r = Math.Max(1, size2);
        for (var dy = -r; dy <= r; dy += pixelSize)
        for (var dx = -r; dx <= r; dx += pixelSize)
        {
            if (dx * dx + dy * dy > r * r) continue;
            var px = (sx + dx + size) % size;
            var py = (sy + dy + size) % size;
            var d = MathF.Sqrt(dx * dx + dy * dy) / Math.Max(1, r);
            var a = Math.Clamp((1f - d * d) * 0.9f, 0f, 1f);
            result.SetPixel(px, py, 1f, 1f, 1f, a);
        }
    }
}
return result;
}
